    bicycle = Bicycle(name=name, description=description, price=price, brand=brand, model=model, category=category, frame_material=frame_material, wheel_size=wheel_size)
    session.add(bicycle)
    session.commit()
    return bicycle

def add_spare_part(session, name, description, price, brand, part_number, bicycle_compatibility):
    spare_part = SparePart(name=name, description=description, price=price, brand=brand, part_number=part_number, bicycle_compatibility=bicycle_compatibility)
    session.add(spare_part)
