import sqlalchemy
from sqlalchemy import create_engine, Column, Integer, String, Float, ForeignKey, Boolean
from sqlalchemy.orm import sessionmaker, relationship
from sqlalchemy.ext.declarative import declarative_base

Base = declarative_base()

class Bicycle(Base):
    __tablename__ = 'bicycles'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    model = Column(String)
    brand = Column(String)
    price = Column(Float)
    description = Column(String)
    in_stock = Column(Integer)

    def __repr__(self):
        return f"<Bicycle(name='{self.name}', model='{self.model}', brand='{self.brand}', price={self.price}, in_stock={self.in_stock})>"

class SparePart(Base):
    __tablename__ = 'spare_parts'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Float)
    bicycle_id = Column(Integer, ForeignKey('bicycles.id'))
    in_stock = Column(Integer)

    bicycle = relationship("Bicycle", back_populates="spare_parts")

    def __repr__(self):
        return f"<SparePart(name='{self.name}', description='{self.description}', price={self.price}, bicycle_id={self.bicycle_id}, in_stock={self.in_stock})>"

Bicycle.spare_parts = relationship("SparePart", order_by=SparePart.id, back_populates="bicycle")


class Accessory(Base):
    __tablename__ = 'accessories'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Float)
    bicycle_id = Column(Integer, ForeignKey('bicycles.id'))
    in_stock = Column(Integer)

    bicycle = relationship("Bicycle", back_populates="accessories")

    def __repr__(self):
        return f"<Accessory(name='{self.name}', description='{self.description}', price={self.price}, bicycle_id={self.bicycle_id}, in_stock={self.in_stock})>"

Bicycle.accessories = relationship("Accessory", order_by=Accessory.id, back_populates="bicycle")


class DatabaseManager:
    def __init__(self, db_name='bicycle_shop.db'):
        self.engine = create_engine(f'sqlite:///{db_name}')
        Base.metadata.create_all(self.engine)
        self.Session = sessionmaker(bind=self.engine)
        self.session = self.Session()

    def add_bicycle(self, name, model, brand, price, description, in_stock):
        bicycle = Bicycle(name=name, model=model, brand=brand, price=price, description=description, in_stock=in_stock)
        self.session.add(bicycle)
        self.session.commit()
        return bicycle

    def get_bicycle(self, bicycle_id):
        return self.session.query(Bicycle).get(bicycle_id)

    def update_bicycle(self, bicycle_id, name=None, model=None, brand=None, price=None, description=None, in_stock=None):
        bicycle = self.get_bicycle(bicycle_id)
        if bicycle:
            if name is not None:
                bicycle.name = name
            if model is not None:
                bicycle.model = model
            if brand is not None:
                bicycle.brand = brand
            if price is not None:
                bicycle.price = price
            if description is not None:
                bicycle.description = description
            if in_stock is not None:
                bicycle.in_stock = in_stock
            self.session.commit()
            return bicycle
        return None

    def delete_bicycle(self, bicycle_id):
        bicycle = self.get_bicycle(bicycle_id)
        if bicycle:
            self.session.delete(bicycle)
            self.session.commit()
            return True
        return False

    def search_bicycles(self, search_term):
        return self.session.query(Bicycle).filter(
            (Bicycle.name.contains(search_term)) |
            (Bicycle.model.contains(search_term)) |
            (Bicycle.brand.contains(search_term)) |
            (Bicycle.description.contains(search_term))
        ).all()

    def filter_bicycles(self, brand=None, min_price=None, max_price=None):
        query = self.session.query(Bicycle)
        if brand:
            query = query.filter(Bicycle.brand == brand)
        if min_price:
            query = query.filter(Bicycle.price >= min_price)
        if max_price:
            query = query.filter(Bicycle.price <= max_price)
        return query.all()

