import sqlalchemy
from sqlalchemy import create_engine, Column, Integer, String, Float, ForeignKey, Boolean
from sqlalchemy.orm import sessionmaker, relationship
from sqlalchemy.ext.declarative import declarative_base

Base = declarative_base()

class Bicycle(Base):
    __tablename__ = 'bicycles'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    brand = Column(String)
    model = Column(String)
    price = Column(Float)
    description = Column(String)
    in_stock = Column(Integer)

    parts = relationship("Part", secondary="bicycle_parts", back_populates="bicycles")
    accessories = relationship("Accessory", secondary="bicycle_accessories", back_populates="bicycles")

    def __repr__(self):
        return f"<Bicycle(name='{self.name}', brand='{self.brand}', model='{self.model}', price={self.price})>"

class Part(Base):
    __tablename__ = 'parts'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Float)
    in_stock = Column(Integer)
    category = Column(String)  # e.g., "Brakes", "Gears", "Wheels"

    bicycles = relationship("Bicycle", secondary="bicycle_parts", back_populates="parts")

    def __repr__(self):
        return f"<Part(name='{self.name}', category='{self.category}', price={self.price})>"

class Accessory(Base):
    __tablename__ = 'accessories'

    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Float)
    in_stock = Column(Integer)
    type = Column(String)  # e.g., "Helmet", "Lights", "Locks"

    bicycles = relationship("Bicycle", secondary="bicycle_accessories", back_populates="accessories")

    def __repr__(self):
        return f"<Accessory(name='{self.name}', type='{self.type}', price={self.price})>"

# Association tables for many-to-many relationships
bicycle_parts = sqlalchemy.Table(
    'bicycle_parts', Base.metadata,
    Column('bicycle_id', Integer, ForeignKey('bicycles.id'), primary_key=True),
    Column('part_id', Integer, ForeignKey('parts.id'), primary_key=True)
)

bicycle_accessories = sqlalchemy.Table(
    'bicycle_accessories', Base.metadata,
    Column('bicycle_id', Integer, ForeignKey('bicycles.id'), primary_key=True),
    Column('accessory_id', Integer, ForeignKey('accessories.id'), primary_key=True)
)


class DatabaseManager:
    def __init__(self, db_url):
        self.engine = create_engine(db_url)
        Base.metadata.create_all(self.engine)
        self.Session = sessionmaker(bind=self.engine)
        self.session = None

    def open_connection(self):
        self.session = self.Session()

    def close_connection(self):
        if self.session:
            self.session.close()
            self.session = None

    def add_bicycle(self, name, brand, model, price, description, in_stock):
        bicycle = Bicycle(name=name, brand=brand, model=model, price=price, description=description, in_stock=in_stock)
        self.session.add(bicycle)
        self.session.commit()
        return bicycle

    def add_part(self, name, description, price, in_stock, category):
        part = Part(name=name, description=description, price=price, in_stock=in_stock, category=category)
        self.session.add(part)
        self.session.commit()
        return part

    def add_accessory(self, name, description, price, in_stock, type):
        accessory = Accessory(name=name, description=description, price=price, in_stock=in_stock, type=type)
        self.session.add(accessory)
        self.session.commit()
        return accessory

    def delete_bicycle(self, bicycle_id):
        bicycle = self.session.query(Bicycle).get(bicycle_id)
        if bicycle:
            self.session.delete(bicycle)
            self.session.commit()
            return True
        return False

    def delete_part(self, part_id):
        part = self.session.query(Part).get(part_id)
        if part:
            self.session.delete(part)
            self.session.commit()
            return True
        return False

    def delete_accessory(self, accessory_id):
        accessory = self.session.query(Accessory).get(accessory_id)
        if accessory:
            self.session.delete(accessory)
            self.session.commit()
            return True
        return False

    def update_bicycle(self, bicycle_id, name=None, brand=None, model=None, price=None, description=None, in_stock=None):
        bicycle = self.session.query(Bicycle).get(bicycle_id)
        if bicycle:
            if name is not None:
                bicycle.name = name
            if brand is not None:
                bicycle.brand = brand
            if model is not None:
                bicycle.model = model
            if price is not None:
                bicycle.price = price
            if description is not None:
                bicycle.description = description
            if in_stock is not None:
                bicycle.in_stock = in_stock
            self.session.commit()
            return bicycle
        return None

    def update_part(self, part_id, name=None, description=None, price=None, in_stock=None, category=None):
        part = self.session.query(Part).get(part_id)
        if part:
            if name is not None:
                part.name = name
            if description is not None:
                part.description = description
            if price is not None:
                part.price = price
            if in_stock is not None:
                part.in_stock = in_stock
            if category is not None:
                part.category = category
            self.session.commit()
            return part
        return None

    def update_accessory(self, accessory_id, name=None, description=None, price=None, in_stock=None, type=None):
        accessory = self.session.query(Accessory).get(accessory_id)
        if accessory:
            if name is not None:
                accessory.name = name
            if description is not None:
                accessory.description = description
            if price is not None:
                accessory.price = price
            if in_stock is not None:
                accessory.in_stock = in_stock
            if type is not None:
                accessory.type = type
            self.session.commit()
            return accessory
        return None

    def get_bicycle(self, bicycle_id):
        return self.session.query(Bicycle).get(bicycle_id)

    def get_part(self, part_id):
        return self.session.query(Part).get(part_id)

    def get_accessory(self, accessory_id):
        return self.session.query(Accessory).get(accessory_id)

    def get_bicycles(self, brand=None, category=None, max_price=None):
        query = self.session.query(Bicycle)
        if brand:
            query = query.filter(Bicycle.brand == brand)
        if max_price:
            query = query.filter(Bicycle.price <= max_price)
        return query.all()

    def get_parts(self, category=None, max_price=None):
        query = self.session.query(Part)
        if category:
            query = query.filter(Part.category == category)
        if max_price:
            query = query.filter(Part.price <= max_price)
        return query.all()

    def get_accessories(self, type=None, max_price=None):
        query = self.session.query(Accessory)
        if type:
            query = query.filter(Accessory.type == type)
        if max_price:
            query = query.filter(Accessory.price <= max_price)
        return query.all()

    def search_bicycles(self, search_term):
        return self.session.query(Bicycle).filter(Bicycle.name.contains(search_term) | Bicycle.brand.contains(search_term) | Bicycle.model.contains(search_term) | Bicycle.description.contains(search_term)).all()

    def search_parts(self, search_term):
        return self.session.query(Part).filter(Part.name.contains(search_term) | Part.description.contains(search_term) | Part.category.contains(search_term)).all()

    def search_accessories(self, search_term):
        return self.session.query(Accessory).filter(Accessory.name.contains(search_term) | Accessory.description.contains(search_term) | Accessory.type.contains(search_term)).all()

    def add_part_to_bicycle(self, bicycle_id, part_id):
        bicycle = self.session.query(Bicycle).get(bicycle_id)
        part = self.session.query(Part).get(part_id)
        if bicycle and part:
            bicycle.parts.append(part)
            self.session.commit()
            return True
        return False

    def add_accessory_to_bicycle(self, bicycle_id, accessory_id):
        bicycle = self.session.query(Bicycle).get(bicycle_id)
        accessory = self.session.query(Accessory).get(accessory_id)
        if bicycle and accessory:
            bicycle.accessories.append(accessory)
            self.session.commit()
            return True
        return False

